yul_optimized:
assembly {
    // staticcall ecrecover — returndatasize is 0x20 on success, 0x00 on failure
    let t := staticcall(gas(), 1, 0x00, 0x80, 0x20, 0x20)
    // Reuse `expiry` variable to carry ecrecover failure signal out of assembly
    expiry := iszero(returndatasize())
    // signer loaded from 0x20 where ecrecover wrote it
    signer := mload(0x20)
}
// Back in Solidity — expiry now means 'ecrecover failed' not 'timestamp exceeded'
if ((nonces(signer) ^ nonce) | expiry != 0) { revert(); }
